   212→func (s *SequentialTests) TestPutDocumentOverwrite() error {
   213→	dbName := GenerateTestDBName()
   214→	defer s.harness.DeleteDatabase(dbName)
   215→
   216→	if err := s.harness.CreateDatabase(dbName); err != nil {
   217→		return err
   218→	}
   219→
   220→	// Create initial document
   221→	doc1 := map[string]interface{}{"version": 1}
   222→	if err := s.harness.PutDocument(dbName+"/doc1", doc1); err != nil {
   223→		return err
   224→	}
   225→
   226→	// Overwrite with mode=overwrite (default)
   227→	doc2 := map[string]interface{}{"version": 2}
   228→	resp, err := s.harness.HTTPRequest("PUT", "/v1/"+dbName+"/doc1?mode=overwrite", doc2)
   229→	if err != nil {
   230→		return err
   231→	}
   232→	if resp.StatusCode != http.StatusOK && resp.StatusCode != http.StatusCreated {
   233→		return fmt.Errorf("expected status 200 or 201, got %d", resp.StatusCode)
   234→	}
   235→
   236→	// Verify overwritten
   237→	result, err := s.harness.GetDocument(dbName + "/doc1")
   238→	if err != nil {
   239→		return err
   240→	}
   241→
   242→	docData, ok := result["doc"].(map[string]interface{})
   243→	if !ok {
   244→		// Try direct access
   245→		if v, ok := result["version"].(float64); ok && v == 2 {
   246→			return nil
   247→		}
   248→		return fmt.Errorf("could not find doc data in response")
   249→	}
   250→
   251→	if v, ok := docData["version"].(float64); !ok || v != 2 {
   252→		return fmt.Errorf("document not overwritten, version=%v", docData["version"])
   253→	}
   254→	return nil
   255→}
