   193→// SSEClient handles Server-Sent Events connections
   194→type SSEClient struct {
   195→	URL      string
   196→	Token    string
   197→	Events   chan SSEEvent
   198→	Done     chan struct{}
   199→	Response *http.Response
   200→	mu       sync.Mutex
   201→}
   202→
   203→// SSEEvent represents a Server-Sent Event
   204→type SSEEvent struct {
   205→	Event string
   206→	Data  string
   207→	ID    string
   208→}
   209→
   210→// NewSSEClient creates a new SSE client
   211→func NewSSEClient(url, token string) *SSEClient {
   212→	return &SSEClient{
   213→		URL:    url,
   214→		Token:  token,
   215→		Events: make(chan SSEEvent, 100),
   216→		Done:   make(chan struct{}),
   217→	}
   218→}
   219→
   220→// Connect connects to the SSE endpoint
   221→func (c *SSEClient) Connect(ctx context.Context) error {
   222→	req, err := http.NewRequestWithContext(ctx, "GET", c.URL, nil)
   223→	if err != nil {
   224→		return err
   225→	}
   226→
   227→	if c.Token != "" {
   228→		req.Header.Set("Authorization", "Bearer "+c.Token)
   229→	}
   230→	req.Header.Set("Accept", "text/event-stream")
   231→
   232→	client := &http.Client{}
   233→	resp, err := client.Do(req)
   234→	if err != nil {
   235→		return err
   236→	}
   237→
   238→	if resp.StatusCode != http.StatusOK {
   239→		resp.Body.Close()
   240→		return fmt.Errorf("unexpected status code: %d", resp.StatusCode)
   241→	}
   242→
   243→	c.mu.Lock()
   244→	c.Response = resp
   245→	c.mu.Unlock()
   246→
   247→	go c.readEvents(resp.Body)
   248→	return nil
   249→}
   250→
   251→// readEvents reads SSE events from the response body
   252→func (c *SSEClient) readEvents(body io.ReadCloser) {
   253→	defer body.Close()
   254→	defer close(c.Events)
   255→
   256→	scanner := bufio.NewScanner(body)
   257→	var event SSEEvent
   258→
   259→	for scanner.Scan() {
   260→		line := scanner.Text()
   261→
   262→		if line == "" {
   263→			// Empty line signals end of event
   264→			if event.Event != "" || event.Data != "" {
   265→				select {
   266→				case c.Events <- event:
   267→				case <-c.Done:
   268→					return
   269→				}
   270→				event = SSEEvent{}
   271→			}
   272→			continue
   273→		}
   274→
   275→		if strings.HasPrefix(line, ":") {
   276→			// Comment line, ignore
   277→			continue
   278→		}
   279→
   280→		if strings.HasPrefix(line, "event:") {
   281→			event.Event = strings.TrimSpace(strings.TrimPrefix(line, "event:"))
   282→		} else if strings.HasPrefix(line, "data:") {
   283→			if event.Data != "" {
   284→				event.Data += "\n"
   285→			}
   286→			event.Data += strings.TrimSpace(strings.TrimPrefix(line, "data:"))
   287→		} else if strings.HasPrefix(line, "id:") {
   288→			event.ID = strings.TrimSpace(strings.TrimPrefix(line, "id:"))
   289→		}
   290→	}
   291→}
   292→
   293→// Close closes the SSE connection
   294→func (c *SSEClient) Close() {
   295→	close(c.Done)
   296→	c.mu.Lock()
   297→	defer c.mu.Unlock()
   298→	if c.Response != nil {
   299→		c.Response.Body.Close()
   300→	}
   301→}
   302→
   303→// WaitForEvent waits for an event with a timeout
   304→func (c *SSEClient) WaitForEvent(timeout time.Duration) (*SSEEvent, error) {
   305→	select {
   306→	case event, ok := <-c.Events:
   307→		if !ok {
   308→			return nil, fmt.Errorf("event channel closed")
   309→		}
   310→		return &event, nil
   311→	case <-time.After(timeout):
   312→		return nil, fmt.Errorf("timeout waiting for event")
   313→	}
   314→}
