    22→// RunAll runs all concurrent tests
    23→func (c *ConcurrentTests) RunAll() []TestResult {
    24→	var results []TestResult
    25→
    26→	tests := []struct {
    27→		name string
    28→		fn   func() error
    29→	}{
    30→		{"ConcurrentPATCHsSameDocument", c.TestConcurrentPATCHsSameDocument},
    31→		{"ConcurrentPATCHDELETESameDocument", c.TestConcurrentPATCHDELETESameDocument},
    32→		{"ConcurrentLoginsSameUser", c.TestConcurrentLoginsSameUser},
    33→		{"LoginLoginPutPut", c.TestLoginLoginPutPut},
    34→		{"ConcurrentPUTsSameDocument", c.TestConcurrentPUTsSameDocument},
    35→		{"ConcurrentGETsCollection", c.TestConcurrentGETsCollection},
    36→		{"ConcurrentDELETEsSameDocument", c.TestConcurrentDELETEsSameDocument},
    37→		{"ConcurrentMixedOperations", c.TestConcurrentMixedOperations},
    38→	}
    39→
    40→	for _, test := range tests {
    41→		start := time.Now()
    42→		err := test.fn()
    43→		duration := time.Since(start)
    44→
    45→		result := TestResult{
    46→			Name:     test.name,
    47→			Passed:   err == nil,
    48→			Duration: duration,
    49→		}
    50→		if err != nil {
    51→			result.Error = err.Error()
    52→		}
    53→		results = append(results, result)
    54→
    55→		if c.t != nil {
    56→			if err != nil {
    57→				c.t.Errorf("%s: %v", test.name, err)
    58→			} else {
    59→				c.t.Logf("%s: PASSED (%v)", test.name, duration)
    60→			}
    61→		}
    62→	}
    63→
    64→	return results
    65→}
