    69→func (c *ConcurrentTests) TestConcurrentPATCHsSameDocument() error {
    70→	dbName := GenerateTestDBName()
    71→	defer c.harness.DeleteDatabase(dbName)
    72→
    73→	if err := c.harness.CreateDatabase(dbName); err != nil {
    74→		return err
    75→	}
    76→
    77→	// Create document with array
    78→	doc := map[string]interface{}{
    79→		"tags": []interface{}{},
    80→	}
    81→	if err := c.harness.PutDocument(dbName+"/doc1", doc); err != nil {
    82→		return err
    83→	}
    84→
    85→	// Launch multiple concurrent PATCH operations
    86→	numGoroutines := 10
    87→	var wg sync.WaitGroup
    88→	errors := make(chan error, numGoroutines)
    89→
    90→	for i := 0; i < numGoroutines; i++ {
    91→		wg.Add(1)
    92→		go func(idx int) {
    93→			defer wg.Done()
    94→			patches := []map[string]interface{}{
    95→				{"op": "ArrayAdd", "path": "/tags", "value": fmt.Sprintf("tag%d", idx)},
    96→			}
    97→			resp, err := c.harness.PatchDocument(dbName+"/doc1", patches)
    98→			if err != nil {
    99→				errors <- fmt.Errorf("goroutine %d: %w", idx, err)
   100→				return
   101→			}
   102→			if resp.StatusCode != http.StatusOK {
   103→				errors <- fmt.Errorf("goroutine %d: unexpected status %d", idx, resp.StatusCode)
   104→			}
   105→		}(i)
   106→	}
   107→
   108→	wg.Wait()
   109→	close(errors)
   110→
   111→	// Check for errors
   112→	for err := range errors {
   113→		return err
   114→	}
   115→
   116→	// Verify the document state
   117→	result, err := c.harness.GetDocument(dbName + "/doc1")
   118→	if err != nil {
   119→		return err
   120→	}
   121→
   122→	docData, ok := result["doc"].(map[string]interface{})
   123→	if !ok {
   124→		docData = result
   125→	}
   126→
   127→	tags, ok := docData["tags"].([]interface{})
   128→	if !ok {
   129→		return fmt.Errorf("tags field not found or not array")
   130→	}
   131→
   132→	// All unique tags should be present (ArrayAdd doesn't add duplicates)
   133→	if len(tags) == 0 {
   134→		return fmt.Errorf("expected some tags, got none")
   135→	}
   136→
   137→	return nil
