// Package skiplist implements a concurrent skip list with lazy synchronization
// and atomics, providing a generic DBIndex interface for the OwlDB database.
package skiplist

import (
	"cmp"
	"context"
	"math/rand"
	"sync"
	"sync/atomic"
)

const maxLevel = 32

// UpdateCheck is called by Upsert while the node is locked. It receives
// the key, the current value (zero value if !exists), and whether the key
// exists. It returns the new value to store, or an error to abort.
type UpdateCheck[K cmp.Ordered, V any] func(key K, currValue V, exists bool) (newValue V, err error)

// Pair holds a key-value pair returned by Query.
type Pair[K cmp.Ordered, V any] struct {
	Key   K
	Value V
}

// node is an internal skip list node.
type node[K cmp.Ordered, V any] struct {
	key        K
	value      V
	next       []*node[K, V]
	marked     atomic.Bool
	fullyLinked atomic.Bool
	mu         sync.Mutex
	topLevel   int
}

// SkipList is a concurrent skip list implementing lazy synchronization.
type SkipList[K cmp.Ordered, V any] struct {
	head   *node[K, V]
	tail   *node[K, V]
	maxKey K
	minKey K
	level  int
}

// New creates a new SkipList. minKey and maxKey are sentinel values that
// must be less than all keys and greater than all keys, respectively.
func New[K cmp.Ordered, V any](minKey, maxKey K) *SkipList[K, V] {
	head := &node[K, V]{
		key:      minKey,
		next:     make([]*node[K, V], maxLevel),
		topLevel: maxLevel - 1,
	}
	head.fullyLinked.Store(true)

	tail := &node[K, V]{
		key:      maxKey,
		next:     make([]*node[K, V], maxLevel),
		topLevel: maxLevel - 1,
	}
	tail.fullyLinked.Store(true)

	for i := 0; i < maxLevel; i++ {
		head.next[i] = tail
	}

	return &SkipList[K, V]{
		head:   head,
		tail:   tail,
		maxKey: maxKey,
		minKey: minKey,
		level:  maxLevel,
	}
}

func randomLevel() int {
	level := 0
	for level < maxLevel-1 && rand.Float64() < 0.5 {
		level++
	}
	return level
}

// findNode finds predecessors and successors at each level.
func (sl *SkipList[K, V]) findNode(key K, preds, succs []*node[K, V]) int {
	found := -1
	pred := sl.head
	for level := maxLevel - 1; level >= 0; level-- {
		curr := pred.next[level]
		for curr != sl.tail && curr.key < key {
			pred = curr
			curr = pred.next[level]
		}
		if found == -1 && curr != sl.tail && curr.key == key {
			found = level
		}
		preds[level] = pred
		succs[level] = curr
	}
	return found
}

// Find returns the value associated with key, or zero value and false if not found.
func (sl *SkipList[K, V]) Find(key K) (V, bool) {
	preds := make([]*node[K, V], maxLevel)
	succs := make([]*node[K, V], maxLevel)
	found := sl.findNode(key, preds, succs)
	if found != -1 {
		n := succs[found]
		if n.fullyLinked.Load() && !n.marked.Load() {
			return n.value, true
		}
	}
	var zero V
	return zero, false
}

// lockPreds locks unique predecessor nodes from level 0 to topLevel.
// Returns the list of unique nodes that were locked, in lock order.
func lockPreds[K cmp.Ordered, V any](preds []*node[K, V], topLevel int) []*node[K, V] {
	var locked []*node[K, V]
	for level := 0; level <= topLevel; level++ {
		pred := preds[level]
		alreadyLocked := false
		for _, l := range locked {
			if l == pred {
				alreadyLocked = true
				break
			}
		}
		if !alreadyLocked {
			pred.mu.Lock()
			locked = append(locked, pred)
		}
	}
	return locked
}

// unlockAll unlocks all nodes in the slice.
func unlockAll[K cmp.Ordered, V any](locked []*node[K, V]) {
	for _, n := range locked {
		n.mu.Unlock()
	}
}

// Upsert atomically updates or inserts a key using the check function.
func (sl *SkipList[K, V]) Upsert(key K, check UpdateCheck[K, V]) (bool, error) {
	topLevel := randomLevel()
	preds := make([]*node[K, V], maxLevel)
	succs := make([]*node[K, V], maxLevel)

	for {
		found := sl.findNode(key, preds, succs)
		if found != -1 {
			nodeFound := succs[found]
			if nodeFound.marked.Load() {
				// Node is being deleted, retry
				continue
			}
			// Wait until fully linked
			for !nodeFound.fullyLinked.Load() {
			}
			// Lock the node for update
			nodeFound.mu.Lock()
			if nodeFound.marked.Load() {
				nodeFound.mu.Unlock()
				continue
			}
			newVal, err := check(key, nodeFound.value, true)
			if err != nil {
				nodeFound.mu.Unlock()
				return false, err
			}
			nodeFound.value = newVal
			nodeFound.mu.Unlock()
			return true, nil
		}

		// Need to insert - lock unique predecessors
		locked := lockPreds(preds, topLevel)

		// Validate that predecessors are still valid
		valid := true
		for level := 0; level <= topLevel; level++ {
			pred := preds[level]
			succ := succs[level]
			if pred.marked.Load() || succ.marked.Load() || pred.next[level] != succ {
				valid = false
				break
			}
		}

		if !valid {
			unlockAll(locked)
			continue
		}

		var zero V
		newVal, err := check(key, zero, false)
		if err != nil {
			unlockAll(locked)
			return false, err
		}

		newNode := &node[K, V]{
			key:      key,
			value:    newVal,
			next:     make([]*node[K, V], topLevel+1),
			topLevel: topLevel,
		}

		for level := 0; level <= topLevel; level++ {
			newNode.next[level] = succs[level]
			preds[level].next[level] = newNode
		}
		newNode.fullyLinked.Store(true)

		unlockAll(locked)
		return false, nil
	}
}

// Remove removes the key from the skip list, returning its value and true,
// or zero value and false if not found.
func (sl *SkipList[K, V]) Remove(key K) (V, bool) {
	var victim *node[K, V]
	isMarked := false
	topLevel := -1
	preds := make([]*node[K, V], maxLevel)
	succs := make([]*node[K, V], maxLevel)
	var zero V

	for {
		found := sl.findNode(key, preds, succs)
		if isMarked || (found != -1 && okToDelete(succs[found], found)) {
			if !isMarked {
				victim = succs[found]
				topLevel = victim.topLevel
				victim.mu.Lock()
				if victim.marked.Load() {
					victim.mu.Unlock()
					return zero, false
				}
				victim.marked.Store(true)
				isMarked = true
			}

			// Lock unique predecessors
			locked := lockPreds(preds, topLevel)

			// Validate
			valid := true
			for level := 0; level <= topLevel; level++ {
				pred := preds[level]
				if pred.marked.Load() || pred.next[level] != victim {
					valid = false
					break
				}
			}

			if !valid {
				unlockAll(locked)
				continue
			}

			for level := topLevel; level >= 0; level-- {
				preds[level].next[level] = victim.next[level]
			}
			victim.mu.Unlock()
			unlockAll(locked)
			return victim.value, true
		}
		return zero, false
	}
}

func okToDelete[K cmp.Ordered, V any](n *node[K, V], found int) bool {
	return n.fullyLinked.Load() && n.topLevel == found && !n.marked.Load()
}

// Query returns all elements with keys in [start, end] in order.
func (sl *SkipList[K, V]) Query(ctx context.Context, start, end K) ([]Pair[K, V], error) {
	var results []Pair[K, V]

	// Find the starting point
	curr := sl.head
	for level := maxLevel - 1; level >= 0; level-- {
		for curr.next[level] != sl.tail && curr.next[level].key < start {
			curr = curr.next[level]
		}
	}
	curr = curr.next[0]

	for curr != sl.tail && curr.key <= end {
		select {
		case <-ctx.Done():
			return results, ctx.Err()
		default:
		}
		if curr.fullyLinked.Load() && !curr.marked.Load() {
			results = append(results, Pair[K, V]{Key: curr.key, Value: curr.value})
		}
		curr = curr.next[0]
	}

	return results, nil
}

// ForEach calls fn for each element in the skip list in order.
// If fn returns false, iteration stops.
func (sl *SkipList[K, V]) ForEach(fn func(key K, value V) bool) {
	curr := sl.head.next[0]
	for curr != sl.tail {
		if curr.fullyLinked.Load() && !curr.marked.Load() {
			if !fn(curr.key, curr.value) {
				return
			}
		}
		curr = curr.next[0]
	}
}

